    ...toBytes(`Thoi gian: ${nowStr}\n\n\n`),
    ...alignCenter,
    ...toBytes("* Cam on quy khach *\n\n\n"),
    ...cutPaper,
  ];
  return buffer
    .map((b) => b.toString(16).padStart(2, "0").toUpperCase())
    .join(" ");
}

