          .toLowerCase()
          .includes(query);
        const queryMatches = !query || codeMatch || nameMatch || billMatch;

        if (!queryMatches) return;

        let filterMatches = true;
        switch (filter) {
          case "available":
          case "empty":
            filterMatches = table.status === "Available";
            break;
          case "serving":
          case "occupied":
            filterMatches =
              table.status === "Serving" || table.status === "Arrived";
            break;
          case "pending":
            filterMatches = table.status === "Arrived";
            break;
          case "printed":
            filterMatches = table.status === "Serving" && table.capacity === 4;
            break;
          case "multi-print":
            filterMatches = table.status === "Serving" && table.capacity !== 4;
            break;
          case "reserved":
          case "multi-bill":
            filterMatches = table.status === "Reserved";
            break;
          case "all":
          default:
            filterMatches = true;
            break;
        }

        if (filterMatches) {
          list.push({
            ...table,
            areaName: area.name,
          });
        }
      });
    }
  });
  return list;
});

